-- Save MJ: Query SQLs (core SP call only)
DO $$
DECLARE
  p_QueryID_c1419578 UUID;
  p_SQLDialectID_c1419578 UUID;
  p_SQL_c1419578 TEXT;
  p_ID_c1419578 UUID;
BEGIN
  p_QueryID_c1419578 := '3366D42B-C3A1-4CE0-9F40-7FBE15F2EA57';
  p_SQLDialectID_c1419578 := '426915F2-D4FE-4AB9-97A8-39063561DE9F';
  p_SQL_c1419578 := '-- PostgreSQL variant for External Change Detection - Detect Creations
SELECT 
    {{ ColumnList }}, ot."{{ CreatedAtField }}" AS "CreatedAt", ot."{{ UpdatedAtField }}" AS "UpdatedAt"
FROM 
    "{{ SchemaName }}"."{{ BaseView }}" ot
LEFT JOIN 
    __mj.vwRecordChanges rc 
    ON 
    ({{ PrimaryKeyJoin }} = rc."RecordID") AND 
    rc."Type" = ''Create'' AND 
    rc."EntityID" = {{ EntityID | sqlString }} 
WHERE 
    rc."RecordID" IS NULL;
';
  p_ID_c1419578 := 'D85DE0AD-5B5B-4EF4-82BC-C634CE39E836';
  PERFORM __mj."spUpdateQuerySQL"(p_QueryID := p_QueryID_c1419578, p_SQLDialectID := p_SQLDialectID_c1419578, p_SQL := p_SQL_c1419578, p_ID := p_ID_c1419578);
END $$;

-- Save MJ: Query SQLs (core SP call only)
DO $$
DECLARE
  p_QueryID_0da7a96f UUID;
  p_SQLDialectID_0da7a96f UUID;
  p_SQL_0da7a96f TEXT;
  p_ID_0da7a96f UUID;
BEGIN
  p_QueryID_0da7a96f := '46A91235-2122-40E8-9289-20D04489CAC5';
  p_SQLDialectID_0da7a96f := '426915F2-D4FE-4AB9-97A8-39063561DE9F';
  p_SQL_0da7a96f := '-- PostgreSQL variant for External Change Detection - Detect Updates
SELECT 
    {{ ColumnList }}, ot."{{ UpdatedAtField }}" AS "UpdatedAt", rc.last_change_time AS "LatestRecordChangeAt"
FROM 
    "{{ SchemaName }}"."{{ BaseView }}" ot
INNER JOIN (
    SELECT 
        RecordID, MAX(ChangedAt) AS last_change_time
    FROM 
        __mj.vwRecordChanges
    WHERE 
        Type IN (''Update'', ''Create'') AND EntityID = {{ EntityID | sqlString }}
    GROUP BY 
        RecordID
) rc ON {{ PrimaryKeyJoin }} = rc."RecordID"
WHERE 
    ot."{{ UpdatedAtField }}" > COALESCE(rc.last_change_time, CAST(''1900-01-01 00:00:00.000'' AS TIMESTAMPTZ));
';
  p_ID_0da7a96f := '565C5AF3-5F59-4531-B21D-53EBC884EF5B';
  PERFORM __mj."spUpdateQuerySQL"(p_QueryID := p_QueryID_0da7a96f, p_SQLDialectID := p_SQLDialectID_0da7a96f, p_SQL := p_SQL_0da7a96f, p_ID := p_ID_0da7a96f);
END $$;

