  p_QueryID_3d0c75bd := '028A39F6-2B38-4ED1-8235-4671B7CD330B';
  p_SQLDialectID_3d0c75bd := '426915F2-D4FE-4AB9-97A8-39063561DE9F';
  p_SQL_3d0c75bd := '-- PostgreSQL variant for External Change Detection - Detect Deletions
-- TECHNICAL DEBT: Joining on dynamically generated PrimaryKeyJoin (a concatenated string) prevents
-- the use of indexes on the organic table (ot). For massive tables, this will result in a table scan.
-- A future schema change to separate RecordID parts into native columns is recommended.
SELECT 
    rc."RecordID", MAX(rc."ChangedAt") AS "ChangedAt"
FROM 
    __mj.vwRecordChanges rc
LEFT JOIN 
    "{{ SchemaName }}"."{{ BaseView }}" ot 
    ON 
    rc."RecordID" = {{ PrimaryKeyJoin }}
WHERE 
    {{ PrimaryKeyIsNull }}
    AND 
        rc."EntityID" = {{ EntityID | sqlString }} 
    AND 
        rc."Type" <> ''Delete''
GROUP BY 
    rc."RecordID"
HAVING 
    MAX(CASE WHEN rc."Type" = ''Delete'' THEN 1 ELSE 0 END) = 0;
';
  p_ID_3d0c75bd := 'F325DCBE-347F-4F59-9A8A-A18706803C8B';
  PERFORM __mj."spUpdateQuerySQL"(p_QueryID := p_QueryID_3d0c75bd, p_SQLDialectID := p_SQLDialectID_3d0c75bd, p_SQL := p_SQL_3d0c75bd, p_ID := p_ID_3d0c75bd);
END $$;

